import { renderHook } from '@testing-library/react';
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { useSwipeGesture } from './useSwipeGesture';

describe('useSwipeGesture', () => {
  const createMockCallback = () => vi.fn() as unknown as () => void;

  afterEach(() => {
    vi.clearAllMocks();
  });

  it('should return a ref object', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: createMockCallback(),
      }),
    );

    expect(result.current.ref).toBeDefined();
    expect(result.current.ref.current).toBeNull();
  });

  it('should accept threshold option', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: createMockCallback(),
        threshold: 150,
      }),
    );

    expect(result.current.ref).toBeDefined();
  });

  it('should accept enabled option set to false', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: createMockCallback(),
        enabled: false,
      }),
    );

    expect(result.current.ref).toBeDefined();
  });

  it('should accept enabled option set to true', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: createMockCallback(),
        enabled: true,
      }),
    );

    expect(result.current.ref).toBeDefined();
  });

  it('should use default threshold when not provided', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: createMockCallback(),
      }),
    );

    expect(result.current.ref).toBeDefined();
  });

  it('should use enabled=true by default', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: createMockCallback(),
      }),
    );

    expect(result.current.ref).toBeDefined();
  });

  it('should accept onSwipeDown callback', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: createMockCallback(),
      }),
    );

    expect(result.current.ref).toBeDefined();
  });

  it('should handle ref changes gracefully', () => {
    const { result } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: createMockCallback(),
        enabled: true,
      }),
    );

    const mockElement1 = document.createElement('div');
    const mockElement2 = document.createElement('div');

    result.current.ref.current = mockElement1;
    result.current.ref.current = mockElement2;
    result.current.ref.current = null;

    expect(result.current.ref.current).toBeNull();
  });

  it('should update when threshold prop changes', () => {
    const callback = createMockCallback();
    const { result, rerender } = renderHook(
      ({ threshold }) =>
        useSwipeGesture({
          onSwipeDown: callback,
          threshold,
        }),
      {
        initialProps: { threshold: 100 },
      },
    );

    expect(result.current.ref).toBeDefined();

    rerender({ threshold: 200 });

    expect(result.current.ref).toBeDefined();
  });

  it('should update when enabled prop changes', () => {
    const callback = createMockCallback();
    const { result, rerender } = renderHook(
      ({ enabled }) =>
        useSwipeGesture({
          onSwipeDown: callback,
          enabled,
        }),
      {
        initialProps: { enabled: true },
      },
    );

    expect(result.current.ref).toBeDefined();

    rerender({ enabled: false });

    expect(result.current.ref).toBeDefined();
  });

  it('should update when onSwipeDown callback changes', () => {
    const { result, rerender } = renderHook(
      ({ callback }) =>
        useSwipeGesture({
          onSwipeDown: callback,
          enabled: true,
        }),
      {
        initialProps: { callback: createMockCallback() },
      },
    );

    expect(result.current.ref).toBeDefined();

    rerender({ callback: createMockCallback() });

    expect(result.current.ref).toBeDefined();
  });

  it('should not throw when unmounting with enabled=true', () => {
    const { result, unmount } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: createMockCallback(),
        enabled: true,
      }),
    );

    result.current.ref.current = document.createElement('div');

    expect(() => unmount()).not.toThrow();
  });

  it('should not throw when unmounting with enabled=false', () => {
    const { result, unmount } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: createMockCallback(),
        enabled: false,
      }),
    );

    result.current.ref.current = document.createElement('div');

    expect(() => unmount()).not.toThrow();
  });

  it('should not throw when unmounting with null ref', () => {
    const { result, unmount } = renderHook(() =>
      useSwipeGesture({
        onSwipeDown: createMockCallback(),
        enabled: true,
      }),
    );

    result.current.ref.current = null;

    expect(() => unmount()).not.toThrow();
  });
});

