import React, { ReactNode, useEffect, useRef } from 'react';
import classNames from 'classnames';
import { createPortal } from 'react-dom';

import './sidebar.scss';

import { useGlobalValue } from 'Shared/store/useGlobalValue';
import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import { SidebarNameE } from 'Components/sidebar/types/SidebarNameE';
import { sidebarService } from 'Services/sidebarService';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import { AuButtonSizeE } from 'Components/form/button/AuButtonSizeE';
import BackSvg from 'Components/svg/BackSvg';
import CloseSvg from 'Components/svg/CloseSvg';
import { SidebarSizeE } from 'Components/sidebar/types/SidebarSizeE';
import { useDidMount } from 'Shared/hooks/useDidMount';
import { scrollLockManager } from 'Services/scrollLockService';
import AuButton from 'Components/form/button/AuButton';
import { useSwipeGesture } from 'Shared/hooks/useSwipeGesture';

const sidebarContainer = document.getElementById('sidebar_portal');

type PropsT = {
  children: ReactNode;
  className?: string;
  headerActions?: ReactNode;
  name: SidebarNameE;
  onBack?: () => void;
  onClose?: () => void;
  title?: string;
  size?: SidebarSizeE;
};

const Sidebar = ({
  children,
  className,
  headerActions,
  name,
  onBack,
  onClose,
  title,
  size = SidebarSizeE.REGULAR,
}: PropsT) => {
  const sidebars = useGlobalValue(GlobalStoreFieldE.SIDEBAR);

  const currentSidebar = sidebars.find(sidebar => sidebar.name === name);
  const sidebarRef = useRef<HTMLDivElement | null>(null);

  const isClosing = Boolean(currentSidebar?.deleted);

  const isMobile = window.matchMedia('(max-width: 59.99rem)').matches;
  // Swipe only for regular size on mobile (medium/small don't block content)
  const enableSwipe = isMobile && size === SidebarSizeE.REGULAR;

  const { ref: swipeRef } = useSwipeGesture({
    onSwipeDown: () => {
      sidebarService.close(name);
    },
    threshold: 100,
    enabled: enableSwipe,
  });

  useDidMount(() => () => {
    onClose?.();

    sidebarService.close(name);
  });

  useEffect(() => {
    if (!currentSidebar) return;

    // Only regular size locks scroll (on both desktop and mobile)
    if (size === SidebarSizeE.REGULAR) {
      scrollLockManager.add(name);

      return () => {
        scrollLockManager.remove(name);
      };
    }
  }, [currentSidebar, name, size]);

  if (!currentSidebar || !sidebarContainer) {
    return null;
  }

  const sidebarKey = `${name}-${currentSidebar?.props ? JSON.stringify(currentSidebar.props) : 'props'}`;

  const handleAnimationEnd = () => {
    if (isClosing) {
      sidebarService.finalizeClose(name);

      onClose?.();
    }
  };

  return createPortal(
    <div
      className={classNames(
        'sidebar-container',
        `sidebar-container--${size}`,
        className,
      )}
      onClick={() => {
        sidebarService.close(name);
      }}
    >
